import java.util.*;class P2{public static void main(String[] a){Scanner s=new Scanner(System.in);int[] x=new int[5];for(int i=0;i<5;i++)x[i]=s.nextInt();for(int i=0;i<5;i++){if(x[i]>0){if(x[i]%2==0)System.out.println("positive even");else System.out.println("positive odd");}else if(x[i]<0)System.out.println("negative");else System.out.println("zero");}if(x[0]==x[4])System.out.println("equal");else if(x[0]>x[4])System.out.println("greater");else System.out.println("less");}}